/* engram-htmx-stub.v1
 *
 * Minimal htmx-compatible shim covering only the attributes the Engram
 * interview Web UI uses: hx-get, hx-post, hx-target, hx-swap (innerHTML,
 * outerHTML, redirect via HX-Redirect response header), and hx-push-url.
 *
 * This is NOT a full htmx implementation. It is intentionally vendored so
 * the operator can run the UI fully offline (D020) without a CDN reference
 * (RFC 0027 F004). Drop in upstream htmx.min.js to gain the full feature
 * set; no other code change is required because this shim publishes the
 * same global "htmx" name and dispatches the "htmx:afterSwap" event on the
 * body that the dispatcher in base.html listens for.
 *
 * License: MIT-style. Authored from the public htmx behavior spec.
 */
(function () {
  "use strict";

  function $(sel, ctx) {
    return (ctx || document).querySelector(sel);
  }

  function resolveTarget(el) {
    var sel = el.getAttribute("hx-target");
    if (!sel) return el;
    if (sel === "this") return el;
    if (sel.indexOf("closest ") === 0) {
      return el.closest(sel.slice(8).trim());
    }
    return $(sel);
  }

  function applySwap(target, mode, html) {
    if (mode === "innerHTML" || !mode) {
      target.innerHTML = html;
    } else if (mode === "outerHTML") {
      var template = document.createElement("template");
      template.innerHTML = html.trim();
      var node = template.content.firstChild;
      if (node && target.parentNode) {
        target.parentNode.replaceChild(node, target);
      } else {
        target.outerHTML = html;
      }
    } else {
      target.innerHTML = html;
    }
    var ev = new CustomEvent("htmx:afterSwap", {
      bubbles: true,
      detail: { target: target },
    });
    document.body.dispatchEvent(ev);
  }

  function performRequest(method, url, body, opts) {
    var xhr = new XMLHttpRequest();
    xhr.open(method, url, true);
    xhr.setRequestHeader("HX-Request", "true");
    xhr.onload = function () {
      var redirect = xhr.getResponseHeader("HX-Redirect");
      if (redirect) {
        window.location.href = redirect;
        return;
      }
      var swapMode = opts.swap || "innerHTML";
      applySwap(opts.target, swapMode, xhr.responseText);
      if (opts.pushUrl) {
        try { history.pushState({}, "", url); } catch (_) {}
      }
    };
    if (method === "POST" && !body) body = "";
    if (body && typeof body !== "string" && body instanceof FormData) {
      // Convert FormData to URL-encoded so the server can read form data
      // without multipart parsing.
      var pairs = [];
      body.forEach(function (v, k) {
        pairs.push(encodeURIComponent(k) + "=" + encodeURIComponent(String(v)));
      });
      body = pairs.join("&");
      xhr.setRequestHeader("Content-Type", "application/x-www-form-urlencoded");
    }
    xhr.send(body || null);
  }

  function attachAttrHandlers(root) {
    var nodes = root.querySelectorAll("[hx-get],[hx-post]");
    for (var i = 0; i < nodes.length; i++) {
      var el = nodes[i];
      if (el.__hxBound) continue;
      // Skip <form>: forms are wired by the dedicated submit-listener loop
      // below so they POST with FormData. Binding a click handler here too
      // would fire a second body-less POST whenever a button inside the
      // form is clicked (the click bubbles up to the form), which races
      // the form's own FormData POST and returns a 422 from the server.
      if (el.tagName === "FORM") continue;
      el.__hxBound = true;
      el.addEventListener("click", function (ev) {
        var node = ev.currentTarget;
        var get = node.getAttribute("hx-get");
        var post = node.getAttribute("hx-post");
        if (!get && !post) return;
        ev.preventDefault();
        var target = resolveTarget(node);
        if (!target) return;
        var swap = node.getAttribute("hx-swap") || "innerHTML";
        var pushUrl = node.getAttribute("hx-push-url") === "true";
        if (get) {
          performRequest("GET", get, null, {
            target: target,
            swap: swap,
            pushUrl: pushUrl,
          });
        } else {
          performRequest("POST", post, null, {
            target: target,
            swap: swap,
            pushUrl: pushUrl,
          });
        }
      });
    }
    var forms = root.querySelectorAll("form[hx-post],form[hx-get]");
    for (var j = 0; j < forms.length; j++) {
      var form = forms[j];
      if (form.__hxBound) continue;
      form.__hxBound = true;
      form.addEventListener("submit", function (ev) {
        var node = ev.currentTarget;
        var post = node.getAttribute("hx-post");
        var get = node.getAttribute("hx-get");
        if (!post && !get) return;
        ev.preventDefault();
        var target = resolveTarget(node);
        if (!target) return;
        var swap = node.getAttribute("hx-swap") || "innerHTML";
        var pushUrl = node.getAttribute("hx-push-url") === "true";
        var data = new FormData(node);
        if (post) {
          performRequest("POST", post, data, {
            target: target,
            swap: swap,
            pushUrl: pushUrl,
          });
        } else {
          // GET: serialize form into query string.
          var pairs = [];
          data.forEach(function (v, k) {
            pairs.push(encodeURIComponent(k) + "=" + encodeURIComponent(String(v)));
          });
          var qs = pairs.join("&");
          var url = get + (qs ? (get.indexOf("?") >= 0 ? "&" : "?") + qs : "");
          performRequest("GET", url, null, {
            target: target,
            swap: swap,
            pushUrl: pushUrl,
          });
        }
      });
    }
  }

  function ready(fn) {
    if (document.readyState !== "loading") fn();
    else document.addEventListener("DOMContentLoaded", fn);
  }

  ready(function () {
    attachAttrHandlers(document);
  });

  // Re-bind on every swap so dynamically inserted nodes wire up.
  document.addEventListener("htmx:afterSwap", function () {
    attachAttrHandlers(document);
  });

  window.htmx = {
    process: attachAttrHandlers,
    version: "engram-stub-1",
  };
})();
